mapper.select:
SELECT c.TABLE_NAME, c.COLUMN_NAME, pk.PK_COLUMN FROM USER_TAB_COLUMNS c INNER JOIN ( SELECT TABLE_NAME, PK_COLUMN FROM ( SELECT cc.TABLE_NAME, cc.COLUMN_NAME AS PK_COLUMN, COUNT(*) OVER (PARTITION BY cc.TABLE_NAME) AS PK_COL_CNT FROM USER_CONSTRAINTS con JOIN USER_CONS_COLUMNS cc ON con.CONSTRAINT_NAME = cc.CONSTRAINT_NAME AND con.TABLE_NAME = cc.TABLE_NAME WHERE con.CONSTRAINT_TYPE = 'P' ) WHERE PK_COL_CNT = 1 ) pk ON c.TABLE_NAME = pk.TABLE_NAME WHERE c.DATA_TYPE IN ('VARCHAR2', 'CHAR', 'NVARCHAR2')
/* ── 해시 컬럼: 복호화 대상 아님 ── */ AND c.COLUMN_NAME NOT LIKE '%\_HASH' ESCAPE '\'
/* ── PK 컬럼 자체 제외 ── */ AND c.COLUMN_NAME != pk.PK_COLUMN
/* ── Phase 1 암호화 보존 컬럼: Phase 2 복호화 제외 ── */ AND NOT (c.TABLE_NAME = 'USERS' AND c.COLUMN_NAME IN ('PHONE', 'CI_VALUE', 'BIRTH_DATE')) AND NOT (c.TABLE_NAME = 'ADMIN_USERS' AND c.COLUMN_NAME = 'PHONE') AND NOT (c.TABLE_NAME = 'WATCHLIST' AND c.COLUMN_NAME IN ('CI_VALUE', 'BIRTH_DATE')) AND NOT (c.TABLE_NAME = 'USER_TRUSTED_IPS' AND c.COLUMN_NAME = 'IP_ADDRESS')
/* ── Phase 1 신규 암호화 대상: Phase 2 복호화 제외 ── */ AND NOT (c.TABLE_NAME = 'EVENT_LOGS' AND c.COLUMN_NAME = 'REQUEST_IP') AND NOT (c.TABLE_NAME = 'LOGIN_HISTORIES' AND c.COLUMN_NAME = 'IP_ADDRESS')
/* ── 원래부터 평문인 컬럼: URL, 콜론 포함 텍스트 ── */ AND NOT (c.TABLE_NAME = 'CARD_BENEFITS' AND c.COLUMN_NAME IN ('BENEFIT_TITLE', 'DISPLAY_TEXT')) AND NOT (c.TABLE_NAME = 'CARD_IMAGES' AND c.COLUMN_NAME = 'IMAGE_URL') AND NOT (c.TABLE_NAME = 'TERMS_FILES' AND c.COLUMN_NAME IN ('FILE_PATH', 'ORIGINAL_NAME', 'STORED_NAME'))
/* ── ★ AUDIT_LOGS 전체 제외: AuditLogDecryptionMigrationService에서 별도 처리 ── */ AND c.TABLE_NAME != 'AUDIT_LOGS'
ORDER BY c.TABLE_NAME, c.COLUMN_NAME

SELECT ${pkColumn} AS PK_VALUE, ${columnName} AS COL_VALUE
FROM   ${tableName}
WHERE  ${columnName} IS NOT NULL
  AND  REGEXP_COUNT(${columnName}, ':') = 1
ORDER BY ${pkColumn}
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY
